## Ablation Pipelines

::: {#cell-ablation-pipelines .cell cache='true' execution_count=7}
``` {.python .cell-code}
from feature_forge.api import MALMASFeatureEngineer

config = Settings(
    task="classification",
    n_rounds=1,
    llm=LLMConfig(
        model="deepseek-chat",
        api_key=os.environ.get("FF_LLM__API_KEY", ""),
    ),
)

X = df.drop(columns=["target"])
y = df["target"]

ablations = {
    "full": "full",
    "no_memory": "no_memory",
    "no_router": "no_router",
    "unary_only": "unary",
}

ablation_results = {}
for name, mode in ablations.items():
    try:
        fe = MALMASFeatureEngineer(config=config, mode=mode)
        fe.fit(X, y)
        ablation_results[name] = {
            "features": len(fe.selected_features),
            "codes": len(fe.feature_codes),
            "transform_failures": len(fe.transform_failures),
        }
    except Exception as exc:
        ablation_results[name] = {"error": str(exc)[:120]}

pd.DataFrame.from_dict(ablation_results, orient="index")
```

